1	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	type DamageEntry = { itemType: string; amount: number };
3	type Incident = { cause: string; damages: DamageEntry[] };
4	type QuoteStep = { op: "quote"; items: Item[] };
5	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
6	type Step = QuoteStep | ClaimStep;
7	type Customer = { yearsWithMHPCO: number };
8	type Scenario = { customer: Customer; steps: Step[] };
9	type QuoteResult = { premium: number };
10	type ClaimResult = { payout: number; remainingCap: number };
11	type StepResult = QuoteResult | ClaimResult;
12	
13	const PROCESSING_FEE = 5;
14	const FIRST_INSURANCE_RATE = 0.1;
15	const CURSE_SURCHARGE_RATE = 0.5;
16	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
17	const HIGH_ENCHANTMENT_THRESHOLD = 5;
18	const LOYALTY_DISCOUNT_RATE = 0.2;
19	const LOYALTY_THRESHOLD_YEARS = 2;
20	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
21	const DEDUCTIBLE = 100;
22	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
23	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
24	const BASE_PREMIUMS: Record<string, number> = {
25	  sword: 100,
26	  amulet: 60,
27	  staff: 80,
28	  potion: 40,
29	  rune: 25,
30	  moonstone: 25,
31	};
32	const INSURANCE_VALUES: Record<string, number> = {
33	  sword: 1000,
34	  amulet: 600,
35	  staff: 800,
36	  potion: 400,
37	  rune: 250,
38	  moonstone: 250,
39	};
40	
41	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
42	const BLOCK_SIZE = 3;
43	const BLOCK_BASE_PREMIUM = 60;
44	
45	const unitBasePremium = (type: string): number => BASE_PREMIUMS[type] ?? 0;
46	
47	const unitInsuranceValue = (type: string): number => INSURANCE_VALUES[type] ?? 0;
48	
49	const isComponentBlock = (type: string, count: number): boolean =>
50	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;
51	
52	const groupBasePremium = (type: string, count: number): number =>
53	  isComponentBlock(type, count) ? BLOCK_BASE_PREMIUM : count * unitBasePremium(type);
54	
55	const countByType = (items: Item[]): Map<string, number> =>
56	  items.reduce(
57	    (counts, item) => counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
58	    new Map<string, number>(),
59	  );
60	
61	const itemsBasePremium = (items: Item[]): number =>
62	  [...countByType(items)].reduce(
63	    (total, [type, count]) => total + groupBasePremium(type, count),
64	    0,
65	  );
66	
67	const enchantmentLevel = (item: Item | undefined): number => item?.enchantment ?? 0;
68	
69	const itemModifierSurcharge = (item: Item): number => {
70	  const base = unitBasePremium(item.type);
71	  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
72	  const highEnchantmentSurcharge =
73	    enchantmentLevel(item) >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0;
74	  return curseSurcharge + highEnchantmentSurcharge;
75	};
76	
77	const itemsModifierSurcharge = (items: Item[]): number =>
78	  items.reduce((total, item) => total + itemModifierSurcharge(item), 0);
79	
80	const loyaltyDiscount = (base: number, customer: Customer): number =>
81	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? base * LOYALTY_DISCOUNT_RATE : 0;
82	
83	const followUpDiscount = (base: number, isFollowUp: boolean): number =>
84	  isFollowUp ? base * FOLLOW_UP_DISCOUNT_RATE : 0;
85	
86	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): number => {
87	  const base = itemsBasePremium(items);
88	  const modifierSurcharge = itemsModifierSurcharge(items);
89	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_RATE;
90	  const discount = loyaltyDiscount(base, customer) + followUpDiscount(base, isFollowUp);
91	  return Math.ceil(base + modifierSurcharge + firstInsuranceSurcharge - discount + PROCESSING_FEE);
92	};
93	
94	const insuranceSum = (items: Item[]): number =>
95	  items.reduce((total, item) => total + unitInsuranceValue(item.type), 0);
96	
97	type Policy = { items: Item[]; capRemaining: number };
98	
99	const createPolicy = (items: Item[]): Policy => ({
100	  items,
101	  capRemaining: 2 * insuranceSum(items),
102	});
103	
104	const findDamagedItem = (policy: Policy, itemType: string): Item | undefined =>
105	  policy.items.find((item) => item.type === itemType);
106	
107	const reimbursableAmount = (item: Item | undefined, damage: DamageEntry): number =>
108	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
109	    ? damage.amount * HIGH_ENCHANTMENT_PAYOUT_RATE
110	    : damage.amount;
111	
112	const damagePayout = (policy: Policy, damage: DamageEntry): number => {
113	  const item = findDamagedItem(policy, damage.itemType);
114	  return Math.max(0, reimbursableAmount(item, damage) - DEDUCTIBLE);
115	};
116	
117	const validateDamageCounts = (policy: Policy, damages: DamageEntry[]): void => {
118	  const insuredCounts = countByType(policy.items);
119	  const damageCounts = damages.reduce(
120	    (counts, damage) => counts.set(damage.itemType, (counts.get(damage.itemType) ?? 0) + 1),
121	    new Map<string, number>(),
122	  );
123	  for (const [type, count] of damageCounts) {
124	    if (count > (insuredCounts.get(type) ?? 0)) {
125	      throw new Error(`More damage entries for ${type} than insured`);
126	    }
127	  }
128	};
129	
130	const processClaim = (policy: Policy, incident: Incident): ClaimResult => {
131	  validateDamageCounts(policy, incident.damages);
132	  const rawPayout = incident.damages.reduce(
133	    (total, damage) => total + damagePayout(policy, damage),
134	    0,
135	  );
136	  const payout = Math.min(rawPayout, policy.capRemaining);
137	  policy.capRemaining -= payout;
138	  return { payout: Math.floor(payout), remainingCap: policy.capRemaining };
139	};
140	
141	const priorQuoteCount = (steps: Step[], upTo: number): number =>
142	  steps.slice(0, upTo).filter((s) => s.op === "quote").length;
143	
144	const handleQuote = (
145	  step: QuoteStep,
146	  index: number,
147	  scenario: Scenario,
148	  policies: Map<number, Policy>,
149	): QuoteResult => {
150	  const isFollowUp = priorQuoteCount(scenario.steps, index) > 0;
151	  policies.set(index, createPolicy(step.items));
152	  return { premium: quotePremium(step.items, scenario.customer, isFollowUp) };
153	};
154	
155	const handleClaim = (step: ClaimStep, policies: Map<number, Policy>): ClaimResult => {
156	  const policy = policies.get(step.policy);
157	  if (!policy) throw new Error(`No policy at index ${step.policy}`);
158	  return processClaim(policy, step.incident);
159	};
160	
161	export const runScenario = (scenario: Scenario): { results: StepResult[] } => {
162	  const policies = new Map<number, Policy>();
163	  const results: StepResult[] = scenario.steps.map((step, index) =>
164	    step.op === "quote"
165	      ? handleQuote(step, index, scenario, policies)
166	      : handleClaim(step, policies),
167	  );
168	  return { results };
169	};
